139	}: {
140		envConfig: Record<string, unknown>;
141	}): EnvironmentVariables {
142		const validatedConfig = plainToInstance(EnvironmentVariables, envConfig, {
143			enableImplicitConversion: true,
144		});
145	
146		const errors = validateSync(validatedConfig, {
147			skipMissingProperties: false,
148			forbidUnknownValues: true,
149			stopAtFirstError: true,
150			forbidNonWhitelisted: true,
151		});
152	
153		if (errors.length > 0) {
154			Logger.error('Config validation error', errors);
155			throw new Error(errors.toString());
156		}
157	
158		return validatedConfig;
159	}
