48	export const loadEnvVariables = (): ConfigFactory[] => {
49		if (isStagingEnv() || isProdEnv()) {
50			validate({ envConfig: getEnvVariables() });
51			return [getEnvVariables];
52		}
53	
54		const envFilePath = path.resolve(process.cwd(), getEnvFile());
55	
56		if (!fs.existsSync(envFilePath)) {
57			if (isDevEnv()) {
58				throw new Error(`Env file not found: ${envFilePath}`);
59			}
60			return [() => ({})];
61		}
62	
63		const envConfig = dotenv.parse(fs.readFileSync(envFilePath));
64	
65		validate({ envConfig });
66	
67		return [() => envConfig];
68	};
